import { AbiString } from "@/mods/string/mod.ts";
import { AbiReadableTuple } from "@/mods/tuple/mod.ts";
import { AbiReadableVector } from "@/mods/vector/mod.ts";
import { Readable } from "@hazae41/binary";
import { test } from "@hazae41/phobos";

test("vector", () => {
  const Vector = new AbiReadableVector(AbiString)
  const Tuple = new AbiReadableTuple([Vector])

  const tuple1 = Tuple.from([["hello", "world"]])
  const tuple2 = Readable.readFromBytes(Tuple, Uint8Array.fromHex(""))

  console.log(tuple1.into()) // -> ["hello", "world"]
  console.log(tuple2.into()) // -> ["hello", "world"]
})